                //rollover para links con imagenes, o sea, boton de mentiritas
            	function btnRoll(link){
                  var va, po;
                  va=link.firstChild.src;
                  po=link.lastChild.src;
                  if(va!=po){
                    link.viejoSrc=va;
                    link.firstChild.src=po;
                  }
            	}
                function btnNormal(link){
                  var va, po;
                  va=link.firstChild.src;
                  po=link.lastChild.src;
                  if(va==po){
                    po=link.viejoSrc;
                    link.firstChild.src=po;
                  }
                }

