function encontrarNodoColapsado(unIdNodo) {
     var h=0; encontroNodo = false;
     var unosIdNodosColapsados = document.getElementById('vistaMenuUsuario_frmMenuUsuario__id32_nodosColapsados');
     if( unosIdNodosColapsados.length){
          for(h = 0; unosIdNodosColapsados.length; h++){
                   if(unosIdNodosColapsados[h].value == unIdNodo){
                      encontroNodo = true;
                   }
          }
     }else{
           if(unosIdNodosColapsados.value == unIdNodo){
                      encontroNodo = true;
           }
     }
     return encontroNodo;
}
function ejecutarEventoExpandir_vistaMenuUsuario_frmMenuUsuario__id32(unIdNodo, unTipoEvento, isNodoInicio, unaOperacionNodo) {
    var isNodoInicial = isNodoInicio == 'false' ? 'false' : 'true' ;
    var cantidadNodos = 0, i =0, j=0, k=0;
    var estadoExpansion = document.getElementById(unIdNodo).getAttribute('expandido');
    if(unaOperacionNodo){
       if(unaOperacionNodo =='expandir' && isNodoInicial=='false'){
          if(document.getElementById(unIdNodo).getAttribute('expandido')=='true'){             estadoExpansion = 'false';          }
       }
    }
    var miTablaTree = document.getElementById('tblNodosTree_id32');
    var tbodyTree = miTablaTree.getElementsByTagName('tbody')[0];
    var unaTablaTmp = document.getElementById('tblNodosTemp_id32');
    var tbodyTmp = unaTablaTmp.getElementsByTagName('tbody')[0];
    if(estadoExpansion =='true'){
       for( i=0; i < miTablaTree.rows.length; i++){
          var miNodo = miTablaTree.rows[i];
          if(miNodo.getAttribute('idCmpPadre') == unIdNodo){
             cantidadNodos = cantidadNodos + 1;
             if(miNodo.getAttribute('expandido')=='true'){
                ejecutarEventoExpandir_vistaMenuUsuario_frmMenuUsuario__id32(miNodo.getAttribute('id'), unTipoEvento, 'false','colapsar');
             }
             miNodo.parentNode.removeChild(miNodo);
             i = i - 1;
             tbodyTmp.appendChild(miNodo);
             var unosIdsNodosColapsados = document.getElementById('vistaMenuUsuario_frmMenuUsuario__id32_nodosColapsados');
             var unObjetoTemporal;
             if(unosIdsNodosColapsados.length){
                   unosIdsNodosColapsados[unosIdsNodosColapsados.length].value = unIdNodo;
             }else{
                   if(!encontrarNodoColapsado(unIdNodo)){
                          unObjetoTemporal = unosIdsNodosColapsados.cloneNode(true);
                          unObjetoTemporal.setAttribute('value',unIdNodo);
                          unosIdsNodosColapsados.parentNode.appendChild(unObjetoTemporal);
                   }
             }
          }
       }
    }else if(estadoExpansion=='false'){
       for( j = unaTablaTmp.rows.length - 1; j >= 0 ; j--){
          var unNodoTmp = unaTablaTmp.rows[j];
          if(unNodoTmp.getAttribute('idCmpPadre') == unIdNodo){
             cantidadNodos = cantidadNodos + 1;
             tbodyTmp.removeChild(unNodoTmp);
             if(document.getElementById(unIdNodo).nextSibling){
                tbodyTree.insertBefore(unNodoTmp,document.getElementById(unIdNodo).nextSibling);
             }else{
                tbodyTree.appendChild(unNodoTmp);
             }
             if(unNodoTmp.getAttribute('expandido')=='true'){
                ejecutarEventoExpandir_vistaMenuUsuario_frmMenuUsuario__id32(unNodoTmp.getAttribute('id'), unTipoEvento, 'false','expandir');                j = unaTablaTmp.rows.length;
             }
             var unosIdsNodosColapsados = document.getElementsByName('vistaMenuUsuario_frmMenuUsuario__id32_nodosColapsados');
             if(unosIdsNodosColapsados.length){
                   for(k = 0; k < unosIdsNodosColapsados.length; k++){
                        if(unosIdsNodosColapsados[k].value == unIdNodo){
                            unosIdsNodosColapsados[k].value = '';
                        }
                   }
             }else{
                  unosIdsNodosColapsados.value='';
             }
          }
       }
    }
    if(cantidadNodos > 0){
       if(isNodoInicial == 'true'){          document.getElementById(unIdNodo).setAttribute('expandido', estadoExpansion=='true' ? 'false' : 'true');
          if( document.getElementById('img'+unIdNodo) ){
             if( estadoExpansion == 'true'  ){
                document.getElementById('img'+unIdNodo).src ='/WebDashboard/imagenes/es/tree/nodoMitadColapsado.gif'             }else{
                document.getElementById('img'+unIdNodo).src ='/WebDashboard/imagenes/es/tree/nodoMitadExpandido.gif'             }
          }
       }
    }
    if(cantidadNodos == 0 && estadoExpansion=='false' && isNodoInicial =='true'){
        ejecutarEvento_vistaMenuUsuario_frmMenuUsuario__id32(unIdNodo, unTipoEvento);
    }
}
function nodoSeleccionado_vistaMenuUsuario_frmMenuUsuario__id32(unIdArbol) {
  var unId = 0;
  var i,fila,index,cadena;
  var treeCategorias = document.getElementById('tblNodosTree'+unIdArbol);
  for(i=0;i< treeCategorias.rows.length;i++){
     fila = treeCategorias.rows[i];
     if(fila.getAttribute('seleccionado')=='true'){
        cadena = fila.getAttribute('id');
        index = cadena.lastIndexOf(':');
        unId = cadena.substring(index+3,cadena.length);
        break;
     }
  }
  return unId;
}


